import{_ as t,o as a,c as o,ag as n}from"./chunks/framework.CxZWPeXl.js";const p=JSON.parse('{"title":"Knowledge Assistant","description":"","frontmatter":{},"headers":[],"relativePath":"en/knowledge-assistant.md","filePath":"en/knowledge-assistant.md"}'),i={name:"en/knowledge-assistant.md"};function r(s,e,l,d,h,u){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="knowledge-assistant" tabindex="-1">Knowledge Assistant <a class="header-anchor" href="#knowledge-assistant" aria-label="Permalink to &quot;Knowledge Assistant&quot;">​</a></h1><blockquote><p>Look up sales knowledge anytime as professional support for your practice.</p></blockquote><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The Knowledge Assistant is a built-in intelligent Q&amp;A feature in AI Coach, based on RAG (Retrieval-Augmented Generation) technology. It retrieves relevant information from the company&#39;s knowledge base to generate accurate answers. You can use it anytime before, during, or after practice.</p><h2 id="how-to-open" tabindex="-1">How to Open <a class="header-anchor" href="#how-to-open" aria-label="Permalink to &quot;How to Open&quot;">​</a></h2><p>Click the <strong>Knowledge Assistant Icon</strong> in the top right navigation bar.</p><blockquote><p>This feature requires knowledge base read permissions. If you do not see the icon, please contact your administrator.</p></blockquote><hr><h2 id="interface-guide" tabindex="-1">Interface Guide <a class="header-anchor" href="#interface-guide" aria-label="Permalink to &quot;Interface Guide&quot;">​</a></h2><h3 id="title-bar" tabindex="-1">Title Bar <a class="header-anchor" href="#title-bar" aria-label="Permalink to &quot;Title Bar&quot;">​</a></h3><ul><li><strong>AI Logo</strong>: Identification icon for the Knowledge Assistant</li><li><strong>AI Chat</strong>: Title text</li><li><strong>Status</strong>: Green dot indicates &quot;Online&quot;; red dot indicates &quot;Offline&quot;</li><li><strong>Clear Chat</strong>: Clear all chat history and start over</li></ul><h3 id="chat-area" tabindex="-1">Chat Area <a class="header-anchor" href="#chat-area" aria-label="Permalink to &quot;Chat Area&quot;">​</a></h3><ul><li><strong>Welcome Screen</strong>: Displayed when first opened, providing usage guidance</li><li><strong>Message List</strong>: Your questions (right) and AI responses (left)</li><li><strong>Typing Indicator</strong>: Animation shown while AI is generating an answer</li></ul><h3 id="suggested-prompt-cards" tabindex="-1">Suggested Prompt Cards <a class="header-anchor" href="#suggested-prompt-cards" aria-label="Permalink to &quot;Suggested Prompt Cards&quot;">​</a></h3><p>Upon entering, you can directly click on the system&#39;s suggested tags:</p><ul><li><strong>Insurance News (保險新知)</strong>: Look up the latest industry trends and news.</li><li><strong>Insurance Q&amp;A Guide (保險問答大補帖)</strong>: Common scripts and customer Q&amp;A references.</li><li><strong>Professional Updates for Agents (保險業務人員的專業新知)</strong>: In-depth professional knowledge and insights.</li><li><strong>Psychology Applications in Insurance (心理學在保險業務中的應用)</strong>: Practical applications of sales psychology.</li></ul><h3 id="input-area" tabindex="-1">Input Area <a class="header-anchor" href="#input-area" aria-label="Permalink to &quot;Input Area&quot;">​</a></h3><ul><li>Input Box: Enter the question you want to look up</li><li>Send Button: Click to send the question (temporarily disabled while AI is answering)</li></ul><hr><h2 id="how-to-use" tabindex="-1">How to Use <a class="header-anchor" href="#how-to-use" aria-label="Permalink to &quot;How to Use&quot;">​</a></h2><ol><li>Click the Knowledge Assistant icon to open the chat window.</li><li>Type your question in the input box.</li><li>Click Send or press Enter.</li><li>Wait for the AI to retrieve data from the knowledge base and respond.</li><li>Review the answer and ask further questions if needed.</li></ol><h2 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use Cases&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Scenario</th><th>Example Question</th></tr></thead><tbody><tr><td>Product Specs</td><td>&quot;What is the coverage of Insurance XX?&quot;</td></tr><tr><td>Script Ref</td><td>&quot;Advice on scripts for customers worried about high premiums?&quot;</td></tr><tr><td>Policy Lookup</td><td>&quot;What is the claims application process?&quot;</td></tr><tr><td>Comparison</td><td>&quot;What is the difference between Plan A and Plan B?&quot;</td></tr><tr><td>FAQs</td><td>&quot;What are the top 3 most common customer questions?&quot;</td></tr></tbody></table><h2 id="important-notes" tabindex="-1">Important Notes <a class="header-anchor" href="#important-notes" aria-label="Permalink to &quot;Important Notes&quot;">​</a></h2><ul><li>The quality of the answers depends on the knowledge base content uploaded by the administrator.</li><li>Answers are for reference only. Please rely on official company documents in actual sales scenarios.</li><li>Chat history is stored locally in your browser.</li><li>Switching accounts or clearing the chat will reset the history.</li></ul><hr><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li>Start <a href="./practice.html">Practice Simulation</a> to apply what you&#39;ve learned</li><li>View <a href="./evaluation.html">Evaluation &amp; Feedback</a> to find areas of improvement</li></ul>',28)])])}const g=t(i,[["render",r]]);export{p as __pageData,g as default};
